enum BiometricAuthError: Error {
    case unavailable
    case canceled
    case failed
}

final class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    private init() {}

    func biometricType() -> LABiometryType {
        let ctx = LAContext()
        _ = ctx.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil)
        return ctx.biometryType
    }

    func canUseBiometrics() -> Bool {
        let ctx = LAContext()
        var error: NSError?
        return ctx.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }

    func authenticate(reason: String, completion: @escaping (Result<Void, Error>) -> Void) {
        let ctx = LAContext()
        ctx.localizedCancelTitle = "Use Password"

        var error: NSError?
        guard ctx.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            DispatchQueue.main.async { completion(.failure(BiometricAuthError.unavailable)) }
            return
        }

        ctx.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, evalError in
            DispatchQueue.main.async {
                if success {
                    completion(.success(()))
                } else {
                    if let laError = evalError as? LAError {
                        switch laError.code {
                        case .userCancel, .appCancel, .systemCancel, .userFallback:
                            completion(.failure(BiometricAuthError.canceled))
                        default:
                            completion(.failure(evalError ?? BiometricAuthError.failed))
                        }
                    } else {
                        completion(.failure(evalError ?? BiometricAuthError.failed))
                    }
                }
            }
        }
    }
}

